599 /// Cmp_match is a variant of BinaryRecipe_match that also binds the comparison
600 /// predicate. Opcodes must either be Instruction::ICmp or Instruction::FCmp, or
601 /// both.
602 template <typename Op0_t, typename Op1_t, unsigned... Opcodes>
603 struct Cmp_match {
604   static_assert((sizeof...(Opcodes) == 1 || sizeof...(Opcodes) == 2) &&
605                 "Expected one or two opcodes");
606   static_assert(
607       ((Opcodes == Instruction::ICmp || Opcodes == Instruction::FCmp) && ...) &&
608       "Expected a compare instruction opcode");
609 
610   CmpPredicate *Predicate = nullptr;
611   Op0_t Op0;
612   Op1_t Op1;
613 
614   Cmp_match(CmpPredicate &Pred, const Op0_t &Op0, const Op1_t &Op1)
615       : Predicate(&Pred), Op0(Op0), Op1(Op1) {}
616   Cmp_match(const Op0_t &Op0, const Op1_t &Op1) : Op0(Op0), Op1(Op1) {}
617 
618   bool match(const VPValue *V) const {
619     auto *DefR = V->getDefiningRecipe();
620     return DefR && match(DefR);
621   }
622 
623   bool match(const VPRecipeBase *V) const {
624     if ((m_Binary<Opcodes>(Op0, Op1).match(V) || ...)) {
625       if (Predicate)
626         *Predicate = cast<VPRecipeWithIRFlags>(V)->getPredicate();
627       return true;
628     }
629     return false;
630   }
631 };
632 
633 /// SpecificCmp_match is a variant of Cmp_match that matches the comparison
634 /// predicate, instead of binding it.
635 template <typename Op0_t, typename Op1_t, unsigned... Opcodes>
636 struct SpecificCmp_match {
637   const CmpPredicate Predicate;
638   Op0_t Op0;
639   Op1_t Op1;
640 
641   SpecificCmp_match(CmpPredicate Pred, const Op0_t &LHS, const Op1_t &RHS)
642       : Predicate(Pred), Op0(LHS), Op1(RHS) {}
643 
644   bool match(const VPValue *V) const {
645     CmpPredicate CurrentPred;
646     return Cmp_match<Op0_t, Op1_t, Opcodes...>(CurrentPred, Op0, Op1)
647                .match(V) &&
648            CmpPredicate::getMatching(CurrentPred, Predicate);
649   }
650 };
